import React from 'react';
import axios from 'axios';
import { OAuth1 } from 'react-native-oauth';

const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const AUTHORIZATION_ENDPOINT = 'https://api.example.com/oauth/authorize';
const ACCESS_TOKEN_URL = 'https://api.example.com/oauth/access_token';
const API_BASE_URL = 'https://api.example.com';

class OAuth extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      isAuthenticated: false,
      accessToken: null,
      requestParams: {},
      error: null,
    };
  }

  handleAuthSuccess = (accessToken, tokenSecret, params) => {
    this.setState({
      isAuthenticated: true,
      accessToken,
      requestParams: params,
    });
  }

  handleAuthFailure = error => {
    this.setState({ error });
  }

  authenticate = () => {
    const auth = new OAuth1(CLIENT_ID, CLIENT_SECRET, AUTHORIZATION_ENDPOINT, ACCESS_TOKEN_URL);
    auth.getOAuthCredentials({}, this.handleAuthSuccess, this.handleAuthFailure);
  }

  fetchAPI = (url, method = 'GET', data = {}) => {
    const headers = {
      'Authorization': `OAuth ${this.state.accessToken}`,
    };

    return axios({
      url: `${API_BASE_URL}${url}`,
      method,
      headers,
      params: data,
    });
  }

  componentDidMount() {
    if (this.state.isAuthenticated) return;
    this.authenticate();
  }

  render() {
    const { isAuthenticated, accessToken, requestParams, error } = this.state;

    // ... your app's UI rendering here based on authentication state and other props
  }
}

